import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({
    StudentID: 1000000,  // Add StudentID
    CGPA: 7.5,
    Internships: 1,
    Projects: 10,
    'Workshops/Certifications': 10,
    AptitudeTestScore: 85,
    SoftSkillsRating: 4.4,
    ExtracurricularActivities: 0,
    PlacementTraining: 0,
    SSC_Marks: 65,
    HSC_Marks: 79
  });

  const [prediction, setPrediction] = useState(null);

  const handleChange = e => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: parseFloat(value) });
  };

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      const res = await axios.post('http://localhost:5000/predict', form);  // Update API URL if needed
      setPrediction(res.data);
    } catch (error) {
      console.error("Error while fetching prediction", error);
    }
  };

  const resultBoxStyle = {
    marginTop: '20px',
    padding: '15px',
    border: '2px solid #ccc',
    borderRadius: '8px',
    width: '300px',
    textAlign: 'center',
    fontSize: '18px',
    fontWeight: 'bold',
    backgroundColor: '#f9f9f9'
  };

  const formStyle = {
    display: 'flex',
    flexDirection: 'column',
    maxWidth: '400px',
    gap: '10px'
  };

  const inputStyle = {
    padding: '8px',
    fontSize: '16px',
    borderRadius: '4px',
    border: '1px solid #ccc'
  };

  const labelStyle = {
    marginBottom: '4px',
    fontWeight: '600'
  };

  return (
    <div style={{ padding: "2rem" }}>
      <h2>Placement Prediction</h2>
      <form onSubmit={handleSubmit} style={formStyle}>
        {Object.keys(form).map(key => (
          <div key={key} style={{ display: 'flex', flexDirection: 'column' }}>
            <label style={labelStyle}>{key}</label>
            <input
              name={key}
              value={form[key]}
              onChange={handleChange}
              type="number"
              step="any"
              style={inputStyle}
            />
          </div>
        ))}
        <button type="submit" style={{ padding: '10px', fontSize: '16px', borderRadius: '6px', cursor: 'pointer' }}>Predict</button>
      </form>
      {prediction !== null && (
        <div style={resultBoxStyle}>
          Student {prediction.StudentID} is{' '}
          {prediction.prediction === 'Placed' ? 'Placed 🙂' : 'Not Placed 🙁'}
        </div>
      )}
    </div>
  );
}

export default App;
